SELECT
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
B.CONTRACT_NUM, B.BAN CUSTOMER_BAN, A.SOC, DECODE(A.SOC,'', '', NVL((SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.SOC AND ROWNUM = 1),A.SOC) ) SERVICE_NM, A.SERVICE_TYPE, F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE) SERVICE_TYPE_NM, PAPER_IMAGE_1, PAPER_IMAGE_2, PAPER_IMAGE_3, PAPER_IMAGE_4, PAPER_IMAGE_5, AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NM, NVL(VIR_ACCOUNT_ID,'') VIR_ACCOUNT_ID, NVL(F_GET_VAC_BANK_NAME(VIR_ACCOUNT_ID),'') VAC_BANK_NM, NVL(F_GET_VAC_BANK_CODE(VIR_ACCOUNT_ID),'') VAC_BANK_CD, NVL(BASIC_REMAINS,0) BASIC_REMAINS, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT, TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS') ENTER_DATE, LANG_CODE, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AD_NATION_NM, B.CUSTOMER_ID, B.SUBSCRIBER_NO, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NM, B.USER_SSN, B.SUB_LINK_NAME, B.MODEL_NAME, B.MODEL_ID, NVL(A.AGENT_SALE_ID,'-') AGENT_SALE_ID, NVL(FN_GET_ORGNM(AGENT_SALE_ID),'-') AGENT_SALE_NM, NVL(AD_NAME, '') AD_NAME, CUST_IDNT_NO_IND_CD, F_GET_KT_CODE_NM('MSP_JUO_CUS_INFO','CUST_IDNT_NO_IND_CD',CUST_IDNT_NO_IND_CD) CUST_IDNT_NO_IND_CD_NM, B.LST_COM_ACTV_DATE, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE, F_GET_KT_CODE_NM('PPS_CUSTOMER','CMS_CHARGE_TYPE',CMS_CHARGE_TYPE) CMS_CHARGE_TYPE_NM, (SELECT MAX(RCG_AMT) FROM PPS_CODE_SERVICE_TOPUP WHERE SOC = A.SOC AND KT_MODE = 'CHG_CASH_REFILL') TOPUP_AMT FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, MSP_RATE_MST C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D, MSP_JUO_CUS_INFO E WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SOC = C.RATE_CD AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND B.CUSTOMER_ID = E.CUSTOMER_ID AND ENTER_DATE > TO_DATE('2013-01-01','YYYY-MM-DD') AND AGENT_ID = #{loginAgentId} AND B.SUB_STATUS IN ('A','S') AND A.SERVICE_TYPE = 'PP' AND C.PAY_CL_CD = 'PP'
AND A.CONTRACT_NUM = #{searchNm}
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND B.CUSTOMER_ID = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND B.USER_SSN = CRYPTO_AES256.ENC_AES(#{searchNm})
AND A.CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM PPS_VAC WHERE VAC_ID = #{searchNm})
AND B.BAN = #{searchNm}
AND ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND BASIC_REMAINS >= #{searchStartRemains}
AND BASIC_REMAINS <= #{searchEndRemains}
AND A.SERVICE_TYPE = #{searchServiceType}
AND A.CONTRACT_NUM = #{contractNum}

SELECT
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
NVL(B.CONTRACT_NUM,0) CONTRACT_NUM, NVL(B.BAN,'-') CUSTOMER_BAN, NVL(A.SOC,'-') SOC, DECODE(A.SOC,'', '-', NVL((SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.SOC AND ROWNUM = 1),A.SOC) ) SERVICE_NM, NVL(A.SERVICE_TYPE,'-') SERVICE_TYPE, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE),'-') SERVICE_TYPE_NM, PAPER_IMAGE_1, PAPER_IMAGE_2, PAPER_IMAGE_3, PAPER_IMAGE_4, PAPER_IMAGE_5, AGENT_ID, NVL(FN_GET_ORGNM(AGENT_ID),'-') AGENT_NM, VIR_ACCOUNT_ID, NVL(BASIC_REMAINS,0) BASIC_REMAINS, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'-') BASIC_EXPIRE, NVL(TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD'),'-') BASIC_EMPT_DT, NVL(TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') ENTER_DATE, LANG_CODE, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AD_NATION_NM, B.CUSTOMER_ID, B.SUBSCRIBER_NO, B.SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS),'-') SUB_STATUS_NM, NVL(B.USER_SSN,'-') USER_SSN, NVL(B.SUB_LINK_NAME,'-') SUB_LINK_NAME, NVL(B.MODEL_NAME,'-') MODEL_NAME, NVL(B.MODEL_ID,'-') MODEL_ID, NVL(B.LST_COM_ACTV_DATE,'-') LST_COM_ACTV_DATE, NVL(A.AGENT_SALE_ID,'-') AGENT_SALE_ID, NVL(FN_GET_ORGNM(AGENT_SALE_ID),'-') AGENT_SALE_NM, NVL(CUST_IDNT_NO_IND_CD, '-') CUST_IDNT_NO_IND_CD, NVL(F_GET_KT_CODE_NM('MSP_JUO_CUS_INFO','CUST_IDNT_NO_IND_CD',CUST_IDNT_NO_IND_CD), '-') CUST_IDNT_NO_IND_CD_NM, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','CMS_CHARGE_TYPE',CMS_CHARGE_TYPE), '-') CMS_CHARGE_TYPE_NM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, MSP_RATE_MST C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D, MSP_JUO_CUS_INFO E WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SOC = C.RATE_CD AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND B.CUSTOMER_ID = E.CUSTOMER_ID AND ENTER_DATE > TO_DATE('2010-01-01','YYYY-MM-DD') AND AGENT_ID = #{loginAgentId} AND B.SUB_STATUS IN ('A','S') AND A.SERVICE_TYPE = 'PP' AND C.PAY_CL_CD = 'PP'
AND A.CONTRACT_NUM = #{searchNm}
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND B.CUSTOMER_ID = #{searchNm}
AND B.USER_SSN = CRYPTO_AES256.ENC_AES(#{searchNm})
AND A.CONTRACT_NUM IN (SELECT CONTRACT_NUM FROM PPS_VAC WHERE VAC_ID = #{searchNm})
AND B.BAN = #{searchNm}
AND ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND BASIC_REMAINS >= #{searchStartRemains}
AND BASIC_REMAINS <= #{searchEndRemains}
AND A.SERVICE_TYPE = #{searchServiceType}

{CALL P_AGENT_CMS_REQ(
			    #{opCode, jdbcType=VARCHAR}
			    , #{seq, jdbcType=VARCHAR}
			    , #{contractNum, jdbcType=VARCHAR}
			    , #{cmsChargeType, jdbcType=VARCHAR}
			    , #{cmsBankCode, jdbcType=VARCHAR}
			    , #{cmsAccount, jdbcType=VARCHAR}
			    , #{cmsCharge, jdbcType=VARCHAR}
			    , #{cmsTryRemains, jdbcType=VARCHAR}
			    , #{cmsChargeDate, jdbcType=VARCHAR}
			    , #{cmsChargeMonth, jdbcType=VARCHAR}
			    , #{status, jdbcType=VARCHAR}
			    , #{adminMemo, jdbcType=VARCHAR}
			    , #{regTypePop, jdbcType=VARCHAR}
			   	, #{fileType, jdbcType=VARCHAR}
			   	, #{fileLen, jdbcType=VARCHAR}
			   	, #{filePath, jdbcType=VARCHAR}
			   	, #{fileEnc, jdbcType=CLOB}
			    , #{agentId, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR} 
			   , #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   , #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }
